'use client';
import Image from 'next/image';
import {
  CalendarDays,
  Clock,
  Locate,
  Users,
  Ticket,
  Building,
  Layers,
  UserCircle,
  CheckCircle2,
  XCircle,
  Loader2,
  CalendarCheck2,
} from 'lucide-react';
import { EventCategory } from '@/types';
import { Button } from '@/components/ui/button';
import { UserRole } from '@/context/AuthContext';
const EventDetails = ({
  event,
  userRole,
}: {
  event: EventCategory;
  userRole: UserRole;
}) => {
  const baseURL = 'http://localhost:8080';
  const src = encodeURI(`${baseURL}/${event?.image?.replace(/\\/g, '/')}`);

  return (
    <div className='min-h-screen bg-white'>
      {/* Hero banner */}
      <section className='relative w-full'>
        <div
          className='relative h-[46vh] md:h-[56vh] lg:h-[64vh] w-full overflow-hidden'
        >
          <div
            className='absolute inset-0'
            style={{
              backgroundImage: `url(${src})`,
              backgroundSize: 'cover',
              backgroundPosition: 'center',
            }}
          />
          <div className='absolute inset-0 bg-gradient-to-b from-black/10 via-black/40 to-black/70' />
          <div className='relative z-10 h-full'>
            <div className='max-w-7xl mx-auto h-full px-6 flex items-end'>
              <div className='w-full'>
                <div className='flex items-center gap-3 mb-4'>
                  {!event.price && (
                    <span className='inline-flex items-center rounded-full bg-green-500/20 text-green-100 px-3 py-1 text-xs font-medium ring-1 ring-inset ring-green-300/30'>FREE</span>
                  )}
                  <span className='inline-flex items-center rounded-full bg-purple-500/20 text-purple-100 px-3 py-1 text-xs font-medium ring-1 ring-inset ring-purple-300/30'>
                    {event.category?.name || 'Event'}
                  </span>
                </div>
                <h1 className='text-white text-3xl md:text-5xl lg:text-6xl font-extrabold tracking-tight drop-shadow-[0_6px_20px_rgba(0,0,0,0.45)]'>
                  {event.title}
                </h1>
                <p className='mt-3 md:mt-4 text-white/90 text-sm md:text-base max-w-2xl'>
                  {event.description}
                </p>
                <div className='mt-5 md:mt-6 flex flex-wrap items-center gap-x-5 gap-y-3 text-sm text-white/90'>
                  <span className='inline-flex items-center gap-2'>
                    <Locate className='w-4 h-4' /> {event.location}
                  </span>
                  <span className='inline-flex items-center gap-2'>
                    <CalendarDays className='w-4 h-4' /> {new Date(event.date).toLocaleDateString()}
                  </span>
                  <span className='inline-flex items-center gap-2'>
                    <Clock className='w-4 h-4' /> {event.time}
                  </span>
                  <span className='inline-flex items-center gap-2'>
                    <Users className='w-4 h-4' /> {event.capacity} capacity
                  </span>
                </div>
                {userRole === 'user' && (
                  <div className='mt-6 flex gap-3'>
                    <Button className='bg-purple-600 hover:bg-purple-700 text-white shadow-lg transition-transform hover:-translate-y-0.5 focus-visible:ring-2 focus-visible:ring-purple-400'>
                      Register Event
                    </Button>
                    <Button
                      variant='outline'
                      className='border-white/60 text-white hover:bg-white hover:text-purple-700 transition-colors'
                    >
                      Learn More
                    </Button>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
      </section>

      {/* Details content */}
      <section className='px-6 py-10 md:py-14'>
        <div className='max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-3 gap-8'>
          <div className='lg:col-span-2'>
            <div className='rounded-xl border border-purple-200/50 shadow-sm p-6 md:p-8 bg-white'>
              <h2 className='text-xl md:text-2xl font-bold text-purple-800 mb-4'>About this event</h2>
              <p className='text-gray-700 leading-relaxed text-sm md:text-base'>
                {event.description}
              </p>
            </div>
          </div>
          <aside className='lg:col-span-1'>
            <div className='rounded-xl border border-purple-200/50 bg-white p-6 md:p-7 shadow-sm'>
              <h3 className='text-base font-semibold text-purple-800 mb-4'>Event information</h3>
              <ul className='space-y-3 text-sm'>
                <li className='flex items-center'>
                  <Building className='w-4 h-4 mr-2 text-purple-600' />
                  <span>Hall: {event.hall?.name || 'Not specified'}</span>
                </li>
                <li className='flex items-center'>
                  <Layers className='w-4 h-4 mr-2 text-purple-600' />
                  <span>Category: {event.category?.name || 'Uncategorized'}</span>
                </li>
                <li className='flex items-center'>
                  <UserCircle className='w-4 h-4 mr-2 text-purple-600' />
                  <span>Host: {event.host}</span>
                </li>
                <li className='flex items-center'>
                  {event.status === 'approved' && (
                    <CheckCircle2 className='w-4 h-4 mr-2 text-green-600' />
                  )}
                  {event.status === 'pending' && (
                    <Loader2 className='w-4 h-4 mr-2 text-yellow-500 animate-spin' />
                  )}
                  {event.status === 'rejected' && (
                    <XCircle className='w-4 h-4 mr-2 text-red-600' />
                  )}
                  <span>Status: {event.status}</span>
                </li>
                <li className='flex items-center'>
                  <CalendarCheck2 className='w-4 h-4 mr-2 text-purple-600' />
                  <span>Starts: {new Date(event.startDate).toLocaleDateString()}</span>
                </li>
                <li className='flex items-center'>
                  <CalendarCheck2 className='w-4 h-4 mr-2 text-purple-600' />
                  <span>Ends: {new Date(event.endDate).toLocaleDateString()}</span>
                </li>
                <li className='flex items-center'>
                  <Ticket className='w-4 h-4 mr-2 text-purple-600' />
                  <span>
                    Entry: {event.price === 0 ? 'Free' : `${event.price} USD`}
                  </span>
                </li>
              </ul>
              <div className='text-[11px] text-gray-500 mt-5'>
                Created at: {new Date(event.createdAt).toLocaleString()} <br />
                Updated at: {new Date(event.updatedAt).toLocaleString()}
              </div>
            </div>
          </aside>
        </div>
      </section>
    </div>
  );
};

export default EventDetails;
